patch:
diff --git a/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp b/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
index ed93b4491c50..9597596e24c4 100644
--- a/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
+++ b/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
@@ -528,19 +528,18 @@ void DeadArgumentEliminationPass::surveyFunction(const Function &F) {
     // change
     if (const auto *TC = BB.getTerminatingMustTailCall()) {
       HasMustTailCalls = true;
-      // In addition, if the called function is not locally defined (or unknown,
-      // if this is an indirect call), we can't change the callsite and thus
-      // can't change this function's signature either.
-      if (!isMustTailCalleeAnalyzable(*TC)) {
-        markLive(F);
-        return;
-      }
+      break;
     }
   }

   if (HasMustTailCalls) {
     LLVM_DEBUG(dbgs() << "DeadArgumentEliminationPass - " << F.getName()
                       << " has musttail calls\n");
+    // Functions with musttail calls cannot have their signatures changed,
+    // regardless of whether the callees are analyzable or not, because
+    // musttail requires exact signature matching between caller and callee.
+    markLive(F);
+    return;
   }

   if (!F.hasLocalLinkage() && (!ShouldHackArguments || F.isIntrinsic())) {
@@ -613,6 +612,11 @@ void DeadArgumentEliminationPass::surveyFunction(const Function &F) {
   if (HasMustTailCallers) {
     LLVM_DEBUG(dbgs() << "DeadArgumentEliminationPass - " << F.getName()
                       << " has musttail callers\n");
+    // Functions that are targets of musttail calls cannot have their signatures
+    // changed, because musttail requires exact signature matching between
+    // caller and callee.
+    markLive(F);
+    return;
   }

   // Now we've inspected all callers, record the liveness of our return values.

