                       << " has musttail calls\n");
+    // Functions with musttail calls cannot have their signatures changed,
+    // regardless of whether the callees are analyzable or not, because
+    // musttail requires exact signature matching between caller and callee.
+    markLive(F);
+    return;
+  }
+
+  // Check if this function has any musttail callers
+  bool HasMustTailCallers = false;
+  for (const Use &U : F.uses()) {
+    const auto *CB = dyn_cast<CallBase>(U.getUser());
+    if (CB && CB->isCallee(&U) && CB->isMustTailCall()) {
+      HasMustTailCallers = true;
+      break;
+    }
+  }
+
+  if (HasMustTailCallers) {
